"use client";

import { Button } from "@/components/ui/button";
import { useForm } from "@tanstack/react-form";
import { useState } from "react";
import * as v from "valibot";
import { updateProfile } from "../_actions/update-profile";

const schema = v.object({
  nickname: v.pipe(
    v.string(),
    v.minLength(1, "ニックネームは必須です"),
    v.maxLength(50, "ニックネームは50文字以内で入力してください"),
  ),
  introduce: v.pipe(
    v.string(),
    v.maxLength(500, "自己紹介は500文字以内で入力してください"),
  ),
});

type Props = {
  defaultNickname: string;
  defaultIntroduce: string;
};

export function ProfileForm({ defaultNickname, defaultIntroduce }: Props) {
  const [successMessage, setSuccessMessage] = useState<string | null>(null);
  const [submitError, setSubmitError] = useState<string | null>(null);

  const form = useForm({
    defaultValues: {
      nickname: defaultNickname,
      introduce: defaultIntroduce,
    },
    onSubmit: async ({ value }) => {
      const result = v.safeParse(schema, value);
      if (!result.success) return;

      setSuccessMessage(null);
      setSubmitError(null);
      const res = await updateProfile(value.nickname, value.introduce);
      if (res.success) {
        setSuccessMessage("プロフィールを保存しました");
        setTimeout(() => setSuccessMessage(null), 3000);
      } else {
        setSubmitError(res.message);
      }
    },
  });

  return (
    <form
      onSubmit={(e) => {
        e.preventDefault();
        form.handleSubmit();
      }}
      className="flex flex-col gap-6 max-w-md"
    >
      <form.Field
        name="nickname"
        validators={{
          onChange: ({ value }) => {
            const result = v.safeParse(
              v.pipe(
                v.string(),
                v.minLength(1, "ニックネームは必須です"),
                v.maxLength(50, "ニックネームは50文字以内で入力してください"),
              ),
              value,
            );
            if (!result.success) return result.issues[0].message;
          },
        }}
      >
        {(field) => (
          <div className="flex flex-col gap-1">
            <label
              htmlFor={field.name}
              className="text-sm font-medium text-foreground"
            >
              ニックネーム
            </label>
            <input
              id={field.name}
              name={field.name}
              value={field.state.value}
              onChange={(e) => field.handleChange(e.target.value)}
              onBlur={field.handleBlur}
              className="border border-border bg-background px-3 py-2 text-sm text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-ring/30 focus:border-ring"
              placeholder="ニックネームを入力"
            />
            {field.state.meta.errors.length > 0 && (
              <p className="text-xs text-destructive">
                {field.state.meta.errors[0]}
              </p>
            )}
          </div>
        )}
      </form.Field>

      <form.Field
        name="introduce"
        validators={{
          onChange: ({ value }) => {
            const result = v.safeParse(
              v.pipe(
                v.string(),
                v.maxLength(500, "自己紹介は500文字以内で入力してください"),
              ),
              value,
            );
            if (!result.success) return result.issues[0].message;
          },
        }}
      >
        {(field) => (
          <div className="flex flex-col gap-1">
            <label
              htmlFor={field.name}
              className="text-sm font-medium text-foreground"
            >
              自己紹介
            </label>
            <textarea
              id={field.name}
              name={field.name}
              value={field.state.value}
              onChange={(e) => field.handleChange(e.target.value)}
              onBlur={field.handleBlur}
              rows={5}
              className="border border-border bg-background px-3 py-2 text-sm text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-ring/30 focus:border-ring resize-none"
              placeholder="自己紹介を入力（任意）"
            />
            {field.state.meta.errors.length > 0 && (
              <p className="text-xs text-destructive">
                {field.state.meta.errors[0]}
              </p>
            )}
          </div>
        )}
      </form.Field>

      {submitError && (
        <p className="text-sm text-destructive">{submitError}</p>
      )}

      {successMessage && (
        <p className="text-sm text-primary">{successMessage}</p>
      )}

      <form.Subscribe selector={(state) => state.isSubmitting}>
        {(isSubmitting) => (
          <Button type="submit" disabled={isSubmitting}>
            {isSubmitting ? "保存中..." : "保存"}
          </Button>
        )}
      </form.Subscribe>
    </form>
  );
}

"use client";

import { Button as ButtonPrimitive } from "@base-ui/react/button";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

const buttonVariants = cva(
  "group/button inline-flex shrink-0 items-center justify-center rounded-md border border-transparent bg-clip-padding font-sans font-bold text-sm uppercase tracking-widest whitespace-nowrap transition-all outline-none select-none focus-visible:border-ring focus-visible:ring-2 focus-visible:ring-ring/30 active:not-aria-[haspopup]:translate-y-px disabled:pointer-events-none disabled:opacity-50 aria-invalid:border-destructive aria-invalid:ring-2 aria-invalid:ring-destructive/20 [&_svg]:pointer-events-none [&_svg]:shrink-0 [&_svg:not([class*='size-'])]:size-4",
  {
    variants: {
      variant: {
        default:
          "relative bg-transparent border border-primary text-primary transition-all duration-350 ease-in overflow-hidden cursor-pointer rounded-none h-auto before:content-[''] before:absolute before:inset-0 before:bg-primary before:scale-x-0 before:origin-left before:transition-transform before:duration-350 before:ease-in before:z-0 hover:before:scale-x-100 hover:text-background hover:shadow-[0_0_16px_oklch(0.75_0.12_77/0.3)]",
        outline:
          "relative bg-transparent border border-border text-muted-foreground transition-all duration-300 ease-in cursor-pointer rounded-none h-auto hover:border-foreground hover:text-foreground",
        secondary:
          "relative bg-transparent border border-secondary text-secondary transition-all duration-350 ease-in overflow-hidden cursor-pointer rounded-none h-auto before:content-[''] before:absolute before:inset-0 before:bg-secondary before:scale-x-0 before:origin-left before:transition-transform before:duration-350 before:ease-in before:z-0 hover:before:scale-x-100 hover:text-secondary-foreground hover:shadow-[0_0_16px_oklch(0.72_0.09_190/0.3)]",
        ghost:
          "hover:bg-muted hover:text-foreground aria-expanded:bg-muted aria-expanded:text-foreground",
        destructive:
          "bg-destructive/10 text-destructive hover:bg-destructive/20 focus-visible:border-destructive/40 focus-visible:ring-destructive/20",
        link: "text-primary underline-offset-4 hover:underline",
      },
      size: {
        default:
          "gap-1 px-8 py-3.5 has-data-[icon=inline-end]:pr-6 has-data-[icon=inline-start]:pl-6 [&_svg:not([class*='size-'])]:size-3.5",
        xs: "h-5 gap-1 rounded-sm px-2 text-[0.625rem] has-data-[icon=inline-end]:pr-1.5 has-data-[icon=inline-start]:pl-1.5 [&_svg:not([class*='size-'])]:size-2.5",
        sm: "gap-1 px-5 py-2 text-xs has-data-[icon=inline-end]:pr-4 has-data-[icon=inline-start]:pl-4 [&_svg:not([class*='size-'])]:size-3",
        lg: "gap-1 px-10 py-4 has-data-[icon=inline-end]:pr-8 has-data-[icon=inline-start]:pl-8 [&_svg:not([class*='size-'])]:size-4 font-black",
        icon: "size-7 [&_svg:not([class*='size-'])]:size-3.5",
        "icon-xs": "size-5 rounded-sm [&_svg:not([class*='size-'])]:size-2.5",
        "icon-sm": "size-6 [&_svg:not([class*='size-'])]:size-3",
        "icon-lg": "size-8 [&_svg:not([class*='size-'])]:size-4",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  },
);

function Button({
  className,
  variant = "default",
  size = "default",
  children,
  ...props
}: ButtonPrimitive.Props & VariantProps<typeof buttonVariants>) {
  const wrapChildren = variant === "default" || variant === "secondary";
  return (
    <ButtonPrimitive
      data-slot="button"
      className={cn(buttonVariants({ variant, size, className }))}
      {...props}
    >
      {wrapChildren ? (
        <span className="relative z-1">{children}</span>
      ) : (
        children
      )}
    </ButtonPrimitive>
  );
}

export { Button, buttonVariants };

