1	"use client";
2	
3	import { Button } from "@/components/ui/button";
4	import { Input } from "@/components/ui/input";
5	import { Label } from "@/components/ui/label";
6	import { Textarea } from "@/components/ui/textarea";
7	import { valibotValidator } from "@tanstack/valibot-form-adapter";
8	import { useForm } from "@tanstack/react-form";
9	import { useState } from "react";
10	import * as v from "valibot";
11	import { updateProfile } from "../_actions/update-profile";
12	
13	const nicknameSchema = v.pipe(
14	  v.string(),
15	  v.minLength(1, "ニックネームは必須です"),
16	  v.maxLength(50, "ニックネームは50文字以内で入力してください"),
17	);
18	
19	const introduceSchema = v.pipe(
20	  v.string(),
21	  v.maxLength(500, "自己紹介は500文字以内で入力してください"),
22	);
23	
24	const schema = v.object({
25	  nickname: nicknameSchema,
26	  introduce: introduceSchema,
27	});
28	
29	type Props = {
30	  defaultNickname: string;
31	  defaultIntroduce: string;
32	};
33	
34	export function ProfileForm({ defaultNickname, defaultIntroduce }: Props) {
35	  const [successMessage, setSuccessMessage] = useState<string | null>(null);
36	  const [submitError, setSubmitError] = useState<string | null>(null);
37	
38	  const form = useForm({
39	    defaultValues: {
40	      nickname: defaultNickname,
41	      introduce: defaultIntroduce,
42	    },
43	    validatorAdapter: valibotValidator(),
44	    validators: {
45	      onChange: schema,
46	    },
47	    onSubmit: async ({ value }) => {
48	      setSuccessMessage(null);
49	      setSubmitError(null);
50	      const res = await updateProfile(value.nickname, value.introduce);
51	      if (res.success) {
52	        setSuccessMessage("プロフィールを保存しました");
53	        setTimeout(() => setSuccessMessage(null), 3000);
54	      } else {
55	        setSubmitError(res.message);
56	      }
57	    },
58	  });
59	
60	  return (
61	    <form
62	      onSubmit={(e) => {
63	        e.preventDefault();
64	        form.handleSubmit();
65	      }}
66	      className="flex flex-col gap-6 max-w-md"
67	    >
68	      <form.Field
69	        name="nickname"
70	        validators={{
71	          onChange: nicknameSchema,
72	        }}
73	      >
74	        {(field) => (
75	          <div className="flex flex-col gap-1">
76	            <Label htmlFor={field.name}>ニックネーム</Label>
77	            <Input
